templates['bars.hbs'] = template({"compiler":[8,">= 4.3.0"],"main":function(container,depth0,helpers,partials,data) {
    return "<div class=\"container\">\n    <div class=\"section\">\n        <div class=\"row\">\n            <h5 class=\"light\">Access Bars® kezelés</h5>\n        </div>\n\n        <div class=\"row\">\n            <div class=\"col s12\">\n\n                <p class=\"light justify-text\">\n                    Az Access Bars® kezelés</br>\n                    - növeli az élethez való pozitív hozzáállásodat</br>\n                    - csökkenti a szorongást</br>\n                    - javítja az alvást</br>\n                    - aktíválja a test öngyógyító képességét</br>\n                    - fejleszti a kreativitást</br>\n                    - javítja a kapcsolatteremtő képességet</br>\n                    - lassítja az öregedési folyamatot</br>\n                    - közelebb kerülhetsz álmaid eléréséhez</br>\n                    - segíti az éberséget, a jelenlétet</br>\n                    - hozzásegít a mély relaxációhoz</br>\n                    - gyógyítja a kapcsolataidat</br>\n                    - képessé válsz a be- és elfogadásra</br>\n                    - egyre több és több lehetőséget kapsz egy boldogabb és teljesebb életre</br>\n                </p>\n                <p class=\"light justify-text\">\n                    Az Access Bars® egy relaxáló és tápláló kezelés, amely segít megváltoztatni számos életterületet,\n                    beleértve az önmagunkkal való kapcsolatot is. Kiválóan alkalmas a stressz és szorongás enyhítésére,\n                    a depresszió és traumák oldására, az alvás, az egészség, a testkép, a pénzzel való kapcsolat\n                    javítására és még ennél is sokkal többre.</br>\n                    </br>\n                    Az Access Bars® kezelés egy gyengéd technika, mely során megérintjük a fejet 32 Access Bars ponton.\n                    Az agy elektromos töltése ekkor eloszlik, aminek köszönhetően az agyban és a testben rekedt energiák\n                    felszabadulnak, és a korlátozásaink könnyedén feloldódnak. A kezelés alatt az agy eléri a théta\n                    állapotot, a mély relaxáció állapotát, amely aktiválja a test öngyógyító képességét és megnyitja a\n                    tudatosság terét az életünkben.</br>\n                    </br>\n                    Az Access Bars kezelés titka, hogy a teljesen ellazult állapot megteremtésével létrehozza azt a\n                    teret, amiben a változás létre tud jönni. Ebben a térben tudunk elkezdeni gyógyulni, itt tudunk\n                    könnyedén elengedni, és itt tud valami teljesen új megszületni.</br>\n                    </br>\n                    Az Access Bars kezelés elkezdi felszabadítani azokat a gondolatokat, érzéseket, érzelmeket,\n                    hiedelmeket és korlátozó programokat, amelyek már nem szolgálnak téged.</br>\n                </p>\n\n                <h5 class=\"light\"> Mi történik egy kezelésen?</h5>\n\n                <p class=\"light justify-text\">\n                    A kezelés fekvésben, masszázságyon történik, időtartama 60 perc. A fejet, kezeket és a lábakat\n                    érintjük,\n                    nincs szükség váltóruhára, de kényelmes öltözet javasolt.\n                </p>\n\n\n\n            </div>\n        </div>\n    </div>\n</div>";
},"useData":true});
