  return "<div class=\"container\">\n  <div class=\"section\">\n    <div class=\"row\">\n      <h1 class=\"light center-text\" style=\"font-size: 2.5rem;\">3 nap jóga, nyugalom és kapcsolódás</h1>\n      <p class=\"center-text\" style=\"font-size: 1.3rem;\"><b>Jóga • Meditáció • Természetközeli pillanatok</b></p>\n    </div>\n\n    <div class=\"row\">\n      <div class=\"col s12 m6\">\n        <p class=\"light justify-text\">\n          Ahogy a természet kikeletkor új életre kel, bennünk is megjelenik a vágy a megújulásra. Hogy megálljunk, meghalljuk mire van szükségünk, fellélegezzünk.<br><br>\n          A Duna közelében, a természet lágy ölén várunk, ahol a levegő tiszta, a nap sugarai játszanak a fák között. A hely nyugalmat ad, a tópart látványa megnyugtatja a lelkedet, és segíti a befelé figyelést.<br><br>\n          Egy támogató közösség vár, ahol jó lenni, ahogy a szívednek jó.<br><br>\n          Minden pillanat lehetőség az ébredésre.\n        </p>\n        <p class=\"light justify-text\">\n          <b>Amiben részesülsz:</b><br>\n          • Könnyed mozgás és ellazulás<br>\n          • Önismereti játékok<br>\n          • Kapcsolódás a természettel<br>\n          • Finom, kemencében sült vegetáriánus ételek helyi zöldségekből<br>\n          • Szauna és jacuzzi\n        </p>\n        <p>\n          <b>Helyszín:</b> Vámosszabadi, Téglás<br>\n          <b>2–6 ágyas szobák, napi 3 vegetáriánus étkezéssel</b>\n        </p>\n        <p>\n          <b>Hozzájárulás:</b> 79.000 Ft<br>\n          <b>Előleg (helyfoglaláshoz):</b> 50.000 Ft<br>\n          <b>Hozz magaddal valakit kedvezménnyel:</b> 75.000 Ft/fő\n        </p>\n        <p>\n          <b>Jelentkezés:</b> <a target=\"_blank\" href=\"https://forms.gle/hQetH21iehgGRh43A\">https://forms.gle/hQetH21iehgGRh43A</a><br>\n          <b>Fizetés:</b> készpénzben vagy utalással<br>\n          OTP: 11773061-08183116<br>\n          Revolut: czviklizs\n        </p>\n        <p>\n          <b>Érkezés:</b> pénteken 14 órától<br>\n          <b>Első jógaóra:</b> 17.30<br>\n          <b>Zárókör:</b> vasárnap 13.00–14.00<br>\n          <b>Létszám:</b> max 15 fő\n        </p>\n      </div>\n      <div class=\"col s12 m6\">\n        <p>\n          <img class=\"responsive-img img-border\" style=\"margin-top: 5px;\" src=\"img/tabor_foto_2026.png\">\n        </p>\n      </div>\n    </div>\n\n    <div class=\"section\">\n      <div class=\"row\">\n        <h5 class=\"light\">Nézz bele a előző táborunkba</h5>\n      </div>\n\n      <div class=\"row\">\n\n"
    + ((stack1 = lookupProperty(helpers,"each").call(depth0 != null ? depth0 : (container.nullContext || {}),(depth0 != null ? lookupProperty(depth0,"images") : depth0),{"name":"each","hash":{},"fn":container.program(1, data, 0),"inverse":container.noop,"data":data,"loc":{"start":{"line":60,"column":8},"end":{"line":67,"column":17}}})) != null ? stack1 : "")
